    pub fn next(&self) -> Option<Self> {
        let guard = &epoch::pin();
        self.inner.next(guard).map(Entry::new)
    }

    /// Returns the previous entry in the map.
    pub fn prev(&self) -> Option<Self> {
        let guard = &epoch::pin();
        self.inner.prev(guard).map(Entry::new)
    }
}

